package classes

import (
	"strconv"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"

	"fitcommerce/backend/internal/auth"
	"fitcommerce/backend/internal/http/response"
	"fitcommerce/backend/internal/middleware"
)

type Handler struct {
	db *pgxpool.Pool
}

func NewHandler(db *pgxpool.Pool) *Handler {
	return &Handler{db: db}
}

func (h *Handler) RegisterRoutes(r gin.IRouter) {
	g := r.Group("/classes")
	g.GET("", h.list)
	g.POST("", middleware.RequireRoles(auth.RoleAdministrator, auth.RoleOperationsManager, auth.RoleCoach), h.create)
	g.GET("/:id", h.get)
	g.PATCH("/:id", middleware.RequireRoles(auth.RoleAdministrator, auth.RoleOperationsManager, auth.RoleCoach), h.update)
	g.POST("/:id/cancel", middleware.RequireRoles(auth.RoleAdministrator, auth.RoleOperationsManager), h.cancel)
	g.POST("/:id/book", h.book)
	g.DELETE("/:id/book", h.cancelBooking)
}

type classResponse struct {
	ID              string `json:"id"`
	CoachID         string `json:"coach_id"`
	LocationID      string `json:"location_id"`
	Name            string `json:"name"`
	Description     *string `json:"description"`
	ScheduledAt     string `json:"scheduled_at"`
	DurationMinutes int    `json:"duration_minutes"`
	Capacity        int    `json:"capacity"`
	BookedSeats     int    `json:"booked_seats"`
	Status          string `json:"status"`
	CreatedAt       string `json:"created_at"`
}

func (h *Handler) list(c *gin.Context) {
	page, _ := strconv.Atoi(c.DefaultQuery("page", "1"))
	perPage, _ := strconv.Atoi(c.DefaultQuery("per_page", "25"))
	if page < 1 { page = 1 }
	if perPage < 1 || perPage > 100 { perPage = 25 }

	var total int
	_ = h.db.QueryRow(c.Request.Context(), `SELECT COUNT(*) FROM classes`).Scan(&total)

	rows, err := h.db.Query(c.Request.Context(), `
		SELECT id, coach_id, location_id, name, description, scheduled_at, duration_minutes, capacity, booked_seats, status, created_at
		FROM classes ORDER BY scheduled_at DESC LIMIT $1 OFFSET $2
	`, perPage, (page-1)*perPage)
	if err != nil { response.InternalError(c); return }
	defer rows.Close()

	classes := []classResponse{}
	for rows.Next() {
		var cl classResponse
		var scheduledAt, createdAt time.Time
		if rows.Scan(&cl.ID, &cl.CoachID, &cl.LocationID, &cl.Name, &cl.Description, &scheduledAt,
			&cl.DurationMinutes, &cl.Capacity, &cl.BookedSeats, &cl.Status, &createdAt) == nil {
			cl.ScheduledAt = scheduledAt.UTC().Format(time.RFC3339)
			cl.CreatedAt = createdAt.UTC().Format(time.RFC3339)
			classes = append(classes, cl)
		}
	}
	response.OKPaginated(c, classes, response.Meta{Page: page, PerPage: perPage, Total: total})
}

func (h *Handler) create(c *gin.Context) { response.NotImplemented(c) }

func (h *Handler) get(c *gin.Context) {
	id := c.Param("id")
	var cl classResponse
	var scheduledAt, createdAt time.Time
	err := h.db.QueryRow(c.Request.Context(), `
		SELECT id, coach_id, location_id, name, description, scheduled_at, duration_minutes, capacity, booked_seats, status, created_at
		FROM classes WHERE id = $1
	`, id).Scan(&cl.ID, &cl.CoachID, &cl.LocationID, &cl.Name, &cl.Description, &scheduledAt,
		&cl.DurationMinutes, &cl.Capacity, &cl.BookedSeats, &cl.Status, &createdAt)
	if err == pgx.ErrNoRows { response.NotFound(c, "class"); return }
	if err != nil { response.InternalError(c); return }
	cl.ScheduledAt = scheduledAt.UTC().Format(time.RFC3339)
	cl.CreatedAt = createdAt.UTC().Format(time.RFC3339)
	response.OK(c, cl)
}

func (h *Handler) update(c *gin.Context)        { response.NotImplemented(c) }
func (h *Handler) cancel(c *gin.Context)        { response.NotImplemented(c) }
func (h *Handler) book(c *gin.Context)          { response.NotImplemented(c) }
func (h *Handler) cancelBooking(c *gin.Context) { response.NotImplemented(c) }

package users

import (
	"crypto/sha256"
	"encoding/hex"
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"

	"fitcommerce/backend/internal/auth"
	"fitcommerce/backend/internal/http/response"
	"fitcommerce/backend/internal/middleware"
	"fitcommerce/backend/internal/modules/audit"
)

type Handler struct {
	db     *pgxpool.Pool
	jwtMgr *auth.Manager
}

func NewHandler(db *pgxpool.Pool, jwtMgr *auth.Manager) *Handler {
	return &Handler{db: db, jwtMgr: jwtMgr}
}

// RegisterRoutes registers protected user-management routes.
// Auth endpoints (login/refresh/logout) are registered separately in the router.
func (h *Handler) RegisterRoutes(r gin.IRouter) {
	g := r.Group("/users")
	g.GET("", h.list)
	g.POST("", h.create)
	g.GET("/me", h.me)
	g.GET("/:id", h.get)
	g.PATCH("/:id", h.update)
	g.DELETE("/:id", h.delete)
}

// ── Request / response types ──────────────────────────────────────────────────

type loginRequest struct {
	Email    string `json:"email" binding:"required,email"`
	Password string `json:"password" binding:"required"`
}

type refreshRequest struct {
	RefreshToken string `json:"refresh_token" binding:"required"`
}

type logoutRequest struct {
	RefreshToken string `json:"refresh_token" binding:"required"`
}

type userResponse struct {
	ID        string `json:"id"`
	Email     string `json:"email"`
	FirstName string `json:"first_name"`
	LastName  string `json:"last_name"`
	Role      string `json:"role"`
	IsActive  bool   `json:"is_active"`
	CreatedAt string `json:"created_at"`
}

// ── Helpers ───────────────────────────────────────────────────────────────────

func hashToken(raw string) string {
	sum := sha256.Sum256([]byte(raw))
	return hex.EncodeToString(sum[:])
}

// ── Public endpoints ──────────────────────────────────────────────────────────

// Login authenticates a user and returns a token pair.
func (h *Handler) Login(c *gin.Context) {
	var req loginRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		response.BadRequest(c, "VALIDATION_ERROR", err.Error())
		return
	}

	// Fetch user by email.
	var (
		id           string
		passwordHash string
		firstName    string
		lastName     string
		role         string
		isActive     bool
		createdAt    time.Time
	)
	err := h.db.QueryRow(c.Request.Context(), `
		SELECT id, password_hash, first_name, last_name, role, is_active, created_at
		FROM users
		WHERE email = $1
	`, req.Email).Scan(&id, &passwordHash, &firstName, &lastName, &role, &isActive, &createdAt)

	if err == pgx.ErrNoRows {
		response.BadRequest(c, "INVALID_CREDENTIALS", "invalid email or password")
		return
	}
	if err != nil {
		response.InternalError(c)
		return
	}
	if !auth.CheckPassword(req.Password, passwordHash) {
		response.BadRequest(c, "INVALID_CREDENTIALS", "invalid email or password")
		return
	}
	if !isActive {
		response.Forbidden(c)
		return
	}

	// Issue token pair.
	pair, err := h.jwtMgr.Issue(id, req.Email, role)
	if err != nil {
		response.InternalError(c)
		return
	}

	// Persist SHA-256 hash of refresh token.
	expiresAt := time.Now().Add(h.jwtMgr.GetRefreshTTL())
	_, err = h.db.Exec(c.Request.Context(), `
		INSERT INTO refresh_tokens (user_id, token_hash, expires_at)
		VALUES ($1, $2, $3)
	`, id, hashToken(pair.RefreshToken), expiresAt)
	if err != nil {
		response.InternalError(c)
		return
	}

	// Fire-and-forget audit event.
	actorID := id
	audit.Log(c.Request.Context(), h.db, &actorID, "user.login", "user", id, nil, nil, c.ClientIP())

	c.JSON(http.StatusOK, gin.H{
		"data": gin.H{
			"access_token":  pair.AccessToken,
			"refresh_token": pair.RefreshToken,
			"expires_in":    pair.ExpiresIn,
			"user": userResponse{
				ID:        id,
				Email:     req.Email,
				FirstName: firstName,
				LastName:  lastName,
				Role:      role,
				IsActive:  isActive,
				CreatedAt: createdAt.UTC().Format(time.RFC3339),
			},
		},
	})
}

// RefreshToken rotates the refresh token.
func (h *Handler) RefreshToken(c *gin.Context) {
	var req refreshRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		response.BadRequest(c, "VALIDATION_ERROR", err.Error())
		return
	}

	// Validate the JWT signature / expiry.
	claims, err := h.jwtMgr.ValidateRefresh(req.RefreshToken)
	if err != nil {
		response.Unauthorized(c)
		return
	}

	// Look up the token hash in DB — must exist, not revoked, not expired.
	tokenHash := hashToken(req.RefreshToken)
	var tokenID string
	err = h.db.QueryRow(c.Request.Context(), `
		SELECT id FROM refresh_tokens
		WHERE token_hash = $1
		  AND revoked_at IS NULL
		  AND expires_at > NOW()
	`, tokenHash).Scan(&tokenID)
	if err == pgx.ErrNoRows {
		response.Unauthorized(c)
		return
	}
	if err != nil {
		response.InternalError(c)
		return
	}

	// Revoke the old token (rotation).
	_, err = h.db.Exec(c.Request.Context(), `
		UPDATE refresh_tokens SET revoked_at = NOW() WHERE id = $1
	`, tokenID)
	if err != nil {
		response.InternalError(c)
		return
	}

	// Fetch user details to embed in new access token.
	var email, role string
	var isActive bool
	err = h.db.QueryRow(c.Request.Context(), `
		SELECT email, role, is_active FROM users WHERE id = $1
	`, claims.UserID).Scan(&email, &role, &isActive)
	if err != nil || !isActive {
		response.Unauthorized(c)
		return
	}

	// Issue new pair.
	pair, err := h.jwtMgr.Issue(claims.UserID, email, role)
	if err != nil {
		response.InternalError(c)
		return
	}

	// Persist new refresh token hash.
	expiresAt := time.Now().Add(h.jwtMgr.GetRefreshTTL())
	_, err = h.db.Exec(c.Request.Context(), `
		INSERT INTO refresh_tokens (user_id, token_hash, expires_at)
		VALUES ($1, $2, $3)
	`, claims.UserID, hashToken(pair.RefreshToken), expiresAt)
	if err != nil {
		response.InternalError(c)
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"data": gin.H{
			"access_token":  pair.AccessToken,
			"refresh_token": pair.RefreshToken,
			"expires_in":    pair.ExpiresIn,
		},
	})
}

// Logout revokes the refresh token. (protected — requires valid access token)
func (h *Handler) Logout(c *gin.Context) {
	var req logoutRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		response.BadRequest(c, "VALIDATION_ERROR", err.Error())
		return
	}

	userID := c.GetString(middleware.KeyUserID)
	tokenHash := hashToken(req.RefreshToken)

	_, _ = h.db.Exec(c.Request.Context(), `
		UPDATE refresh_tokens
		SET revoked_at = NOW()
		WHERE token_hash = $1 AND user_id = $2 AND revoked_at IS NULL
	`, tokenHash, userID)

	actorID := userID
	audit.Log(c.Request.Context(), h.db, &actorID, "user.logout", "user", userID, nil, nil, c.ClientIP())

	response.NoContent(c)
}

// ── Protected endpoints ───────────────────────────────────────────────────────

func (h *Handler) me(c *gin.Context) {
	userID := c.GetString(middleware.KeyUserID)

	var u userResponse
	var createdAt time.Time
	err := h.db.QueryRow(c.Request.Context(), `
		SELECT id, email, first_name, last_name, role, is_active, created_at
		FROM users WHERE id = $1
	`, userID).Scan(&u.ID, &u.Email, &u.FirstName, &u.LastName, &u.Role, &u.IsActive, &createdAt)
	if err == pgx.ErrNoRows {
		response.NotFound(c, "user")
		return
	}
	if err != nil {
		response.InternalError(c)
		return
	}
	u.CreatedAt = createdAt.UTC().Format(time.RFC3339)
	response.OK(c, u)
}

func (h *Handler) list(c *gin.Context) {
	response.NotImplemented(c)
}

func (h *Handler) create(c *gin.Context) {
	response.NotImplemented(c)
}

func (h *Handler) get(c *gin.Context) {
	response.NotImplemented(c)
}

func (h *Handler) update(c *gin.Context) {
	response.NotImplemented(c)
}

func (h *Handler) delete(c *gin.Context) {
	response.NotImplemented(c)
}

import { createBrowserRouter, Navigate } from 'react-router-dom';
import { ProtectedRoute } from '../components/auth/ProtectedRoute';
import { AppLayout } from '../layouts/AppLayout';
import { LoginPage } from '../pages/LoginPage';
import { ForbiddenPage } from '../pages/ForbiddenPage';
import { PlaceholderPage } from '../pages/PlaceholderPage';
import { ItemListPage } from '../pages/items/ItemListPage';
import { ItemFormPage } from '../pages/items/ItemFormPage';
import { ItemDetailPage } from '../pages/items/ItemDetailPage';
import { InventoryListPage } from '../pages/inventory/InventoryListPage';
import { SupplierListPage } from '../pages/suppliers/SupplierListPage';
import { SupplierFormPage } from '../pages/suppliers/SupplierFormPage';
import { POListPage } from '../pages/purchaseorders/POListPage';
import { POFormPage } from '../pages/purchaseorders/POFormPage';
import { PODetailPage } from '../pages/purchaseorders/PODetailPage';
import { GroupBuyListPage } from '../pages/groupbuys/GroupBuyListPage';
import { GroupBuyDetailPage } from '../pages/groupbuys/GroupBuyDetailPage';
import { GroupBuyCreatePage } from '../pages/groupbuys/GroupBuyCreatePage';
import { OrderListPage } from '../pages/orders/OrderListPage';
import { OrderDetailPage } from '../pages/orders/OrderDetailPage';
import { DashboardPage } from '../pages/DashboardPage';
import { ReportsPage } from '../pages/ReportsPage';

export const router = createBrowserRouter([
  // ── Public routes ──────────────────────────────────────────────────────────
  { path: '/login', element: <LoginPage /> },
  { path: '/forbidden', element: <ForbiddenPage /> },

  // ── Protected shell ────────────────────────────────────────────────────────
  {
    path: '/',
    element: (
      <ProtectedRoute>
        <AppLayout />
      </ProtectedRoute>
    ),
    children: [
      { index: true, element: <Navigate to="/dashboard" replace /> },

      { path: 'dashboard', element: <DashboardPage /> },

      // ── Catalog (items) ──────────────────────────────────────────────────
      {
        path: 'items',
        element: <ItemListPage />,
      },
      {
        path: 'items/new',
        element: (
          <ProtectedRoute roles={['administrator', 'operations_manager']}>
            <ItemFormPage />
          </ProtectedRoute>
        ),
      },
      {
        path: 'items/:id',
        element: <ItemDetailPage />,
      },
      {
        path: 'items/:id/edit',
        element: (
          <ProtectedRoute roles={['administrator', 'operations_manager']}>
            <ItemFormPage />
          </ProtectedRoute>
        ),
      },

      // ── Inventory ────────────────────────────────────────────────────────
      {
        path: 'inventory',
        element: (
          <ProtectedRoute roles={['administrator', 'operations_manager', 'procurement_specialist']}>
            <InventoryListPage />
          </ProtectedRoute>
        ),
      },

      // ── Suppliers ────────────────────────────────────────────────────────
      {
        path: 'suppliers',
        element: (
          <ProtectedRoute roles={['administrator', 'procurement_specialist']}>
            <SupplierListPage />
          </ProtectedRoute>
        ),
      },
      {
        path: 'suppliers/new',
        element: (
          <ProtectedRoute roles={['administrator', 'procurement_specialist']}>
            <SupplierFormPage />
          </ProtectedRoute>
        ),
      },
      {
        path: 'suppliers/:id/edit',
        element: (
          <ProtectedRoute roles={['administrator', 'procurement_specialist']}>
            <SupplierFormPage />
          </ProtectedRoute>
        ),
      },

      // ── Purchase Orders ──────────────────────────────────────────────────
      {
        path: 'purchase-orders',
        element: (
          <ProtectedRoute roles={['administrator', 'procurement_specialist']}>
            <POListPage />
          </ProtectedRoute>
        ),
      },
      {
        path: 'purchase-orders/new',
        element: (
          <ProtectedRoute roles={['administrator', 'procurement_specialist']}>
            <POFormPage />
          </ProtectedRoute>
        ),
      },
      {
        path: 'purchase-orders/:id',
        element: (
          <ProtectedRoute roles={['administrator', 'procurement_specialist']}>
            <PODetailPage />
          </ProtectedRoute>
        ),
      },

      // ── Group Buys ─────────────────────────────────────────────────────
      {
        path: 'group-buys',
        element: <GroupBuyListPage />,
      },
      {
        path: 'group-buys/new',
        element: <GroupBuyCreatePage />,
      },
      {
        path: 'group-buys/:id',
        element: <GroupBuyDetailPage />,
      },
      {
        path: 'orders',
        element: (
          <ProtectedRoute roles={['administrator', 'operations_manager', 'member']}>
            <OrderListPage />
          </ProtectedRoute>
        ),
      },
      {
        path: 'orders/:id',
        element: (
          <ProtectedRoute roles={['administrator', 'operations_manager', 'member']}>
            <OrderDetailPage />
          </ProtectedRoute>
        ),
      },
      {
        path: 'reports',
        element: (
          <ProtectedRoute roles={['administrator', 'operations_manager', 'procurement_specialist', 'coach']}>
            <ReportsPage />
          </ProtectedRoute>
        ),
      },
      {
        path: 'classes',
        element: (
          <ProtectedRoute roles={['administrator', 'operations_manager', 'coach']}>
            <PlaceholderPage title="Classes" />
          </ProtectedRoute>
        ),
      },
      {
        path: 'admin',
        element: (
          <ProtectedRoute roles={['administrator']}>
            <PlaceholderPage title="Administration" />
          </ProtectedRoute>
        ),
      },
    ],
  },

  // Catch-all
  { path: '*', element: <Navigate to="/dashboard" replace /> },
]);

