package members

import (
	"strconv"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"

	"fitcommerce/backend/internal/auth"
	"fitcommerce/backend/internal/http/response"
	"fitcommerce/backend/internal/middleware"
)

type Handler struct {
	db *pgxpool.Pool
}

func NewHandler(db *pgxpool.Pool) *Handler {
	return &Handler{db: db}
}

func (h *Handler) RegisterRoutes(r gin.IRouter) {
	g := r.Group("/members")
	g.GET("", h.list)
	g.POST("", middleware.RequireRoles(auth.RoleAdministrator, auth.RoleOperationsManager), h.create)
	g.GET("/:id", h.get)
	g.PATCH("/:id", middleware.RequireRoles(auth.RoleAdministrator, auth.RoleOperationsManager), h.update)
	g.GET("/:id/orders", h.orders)
	g.GET("/:id/group-buys", h.groupBuys)
}

type memberResponse struct {
	ID             string  `json:"id"`
	UserID         string  `json:"user_id"`
	LocationID     *string `json:"location_id"`
	MembershipType string  `json:"membership_type"`
	MembershipStart *string `json:"membership_start"`
	MembershipEnd   *string `json:"membership_end"`
	Status         string  `json:"status"`
	CreatedAt      string  `json:"created_at"`
}

func (h *Handler) list(c *gin.Context) {
	page, _ := strconv.Atoi(c.DefaultQuery("page", "1"))
	perPage, _ := strconv.Atoi(c.DefaultQuery("per_page", "25"))
	if page < 1 { page = 1 }
	if perPage < 1 || perPage > 100 { perPage = 25 }

	var total int
	_ = h.db.QueryRow(c.Request.Context(), `SELECT COUNT(*) FROM members`).Scan(&total)

	rows, err := h.db.Query(c.Request.Context(), `
		SELECT id, user_id, location_id, membership_type, membership_start::text, membership_end::text, status, created_at
		FROM members ORDER BY created_at DESC LIMIT $1 OFFSET $2
	`, perPage, (page-1)*perPage)
	if err != nil { response.InternalError(c); return }
	defer rows.Close()

	members := []memberResponse{}
	for rows.Next() {
		var m memberResponse
		var createdAt time.Time
		if rows.Scan(&m.ID, &m.UserID, &m.LocationID, &m.MembershipType, &m.MembershipStart, &m.MembershipEnd, &m.Status, &createdAt) == nil {
			m.CreatedAt = createdAt.UTC().Format(time.RFC3339)
			members = append(members, m)
		}
	}
	response.OKPaginated(c, members, response.Meta{Page: page, PerPage: perPage, Total: total})
}

func (h *Handler) create(c *gin.Context) {
	response.NotImplemented(c)
}

func (h *Handler) get(c *gin.Context) {
	id := c.Param("id")
	var m memberResponse
	var createdAt time.Time
	err := h.db.QueryRow(c.Request.Context(), `
		SELECT id, user_id, location_id, membership_type, membership_start::text, membership_end::text, status, created_at
		FROM members WHERE id = $1
	`, id).Scan(&m.ID, &m.UserID, &m.LocationID, &m.MembershipType, &m.MembershipStart, &m.MembershipEnd, &m.Status, &createdAt)
	if err == pgx.ErrNoRows { response.NotFound(c, "member"); return }
	if err != nil { response.InternalError(c); return }
	m.CreatedAt = createdAt.UTC().Format(time.RFC3339)
	response.OK(c, m)
}

func (h *Handler) update(c *gin.Context) {
	response.NotImplemented(c)
}

func (h *Handler) orders(c *gin.Context) {
	memberID := c.Param("id")
	rows, err := h.db.Query(c.Request.Context(), `
		SELECT id, status, total_amount, created_at FROM orders WHERE member_id = $1 ORDER BY created_at DESC
	`, memberID)
	if err != nil { response.InternalError(c); return }
	defer rows.Close()

	type orderSummary struct {
		ID        string  `json:"id"`
		Status    string  `json:"status"`
		Total     float64 `json:"total_amount"`
		CreatedAt string  `json:"created_at"`
	}
	results := []orderSummary{}
	for rows.Next() {
		var o orderSummary
		var createdAt time.Time
		if rows.Scan(&o.ID, &o.Status, &o.Total, &createdAt) == nil {
			o.CreatedAt = createdAt.UTC().Format(time.RFC3339)
			results = append(results, o)
		}
	}
	response.OK(c, results)
}

func (h *Handler) groupBuys(c *gin.Context) {
	memberID := c.Param("id")
	rows, err := h.db.Query(c.Request.Context(), `
		SELECT g.id, g.title, g.status, p.quantity, p.joined_at
		FROM group_buy_participants p
		JOIN group_buys g ON g.id = p.group_buy_id
		WHERE p.member_id = $1
		ORDER BY p.joined_at DESC
	`, memberID)
	if err != nil { response.InternalError(c); return }
	defer rows.Close()

	type gbSummary struct {
		ID       string `json:"id"`
		Title    string `json:"title"`
		Status   string `json:"status"`
		Quantity int    `json:"quantity"`
		JoinedAt string `json:"joined_at"`
	}
	results := []gbSummary{}
	for rows.Next() {
		var g gbSummary
		var joinedAt time.Time
		if rows.Scan(&g.ID, &g.Title, &g.Status, &g.Quantity, &joinedAt) == nil {
			g.JoinedAt = joinedAt.UTC().Format(time.RFC3339)
			results = append(results, g)
		}
	}
	response.OK(c, results)
}

// Package syncsvc handles offline-sync endpoints.
// Named syncsvc to avoid collision with the stdlib sync package.
package syncsvc

import (
	"strconv"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/redis/go-redis/v9"

	"fitcommerce/backend/internal/http/response"
	"fitcommerce/backend/internal/middleware"
)

type Handler struct {
	db  *pgxpool.Pool
	rdb *redis.Client
}

func NewHandler(db *pgxpool.Pool, rdb *redis.Client) *Handler {
	return &Handler{db: db, rdb: rdb}
}

func (h *Handler) RegisterRoutes(r gin.IRouter) {
	g := r.Group("/sync")
	g.GET("/changes", h.changes)
	g.POST("/push", h.push)
	g.POST("/resolve", h.resolve)
}

// ── Types ─────────────────────────────────────────────────────────────────────

type pushRequest struct {
	Mutations []mutationInput `json:"mutations" binding:"required,min=1"`
}

type mutationInput struct {
	IdempotencyKey string                 `json:"idempotency_key" binding:"required"`
	ClientID       string                 `json:"client_id" binding:"required"`
	EntityType     string                 `json:"entity_type" binding:"required"`
	EntityID       string                 `json:"entity_id"`
	Operation      string                 `json:"operation" binding:"required"`
	Payload        map[string]interface{} `json:"payload" binding:"required"`
}

type resolveRequest struct {
	MutationID string `json:"mutation_id" binding:"required"`
	Resolution string `json:"resolution" binding:"required"` // "accept_client" | "accept_server" | "discard"
}

// ── Changes endpoint — delta pull ─────────────────────────────────────────────

func (h *Handler) changes(c *gin.Context) {
	sinceStr := c.DefaultQuery("since", "0")
	sinceUnix, _ := strconv.ParseInt(sinceStr, 10, 64)
	since := time.Unix(sinceUnix, 0)

	entities := c.DefaultQuery("entities", "items")
	entityList := strings.Split(entities, ",")

	result := map[string]interface{}{}

	for _, entity := range entityList {
		switch strings.TrimSpace(entity) {
		case "items":
			rows, err := h.db.Query(c.Request.Context(), `
				SELECT id, name, description, category, brand, condition, billing_model,
					deposit_amount, price, status, location_id, version, updated_at
				FROM items WHERE updated_at > $1
				ORDER BY updated_at LIMIT 500
			`, since)
			if err == nil {
				result["items"] = scanItems(rows)
			}
		case "group_buys":
			rows, err := h.db.Query(c.Request.Context(), `
				SELECT g.id, g.item_id, i.name, g.title, g.description, g.min_quantity,
					g.current_quantity, g.status, g.cutoff_at, g.price_per_unit,
					g.location_id, g.version, g.updated_at
				FROM group_buys g JOIN items i ON i.id = g.item_id
				WHERE g.updated_at > $1
				ORDER BY g.updated_at LIMIT 500
			`, since)
			if err == nil {
				result["group_buys"] = scanGroupBuys(rows)
			}
		case "orders":
			userID := c.GetString(middleware.KeyUserID)
			rows, err := h.db.Query(c.Request.Context(), `
				SELECT o.id, o.member_id, o.status, o.total_amount, o.deposit_amount,
					o.group_buy_id, o.version, o.updated_at
				FROM orders o
				JOIN members m ON m.id = o.member_id
				WHERE o.updated_at > $1 AND m.user_id = $2
				ORDER BY o.updated_at LIMIT 500
			`, since, userID)
			if err == nil {
				result["orders"] = scanOrders(rows)
			}
		case "members":
			rows, err := h.db.Query(c.Request.Context(), `
				SELECT id, user_id, location_id, membership_type, status, version, updated_at
				FROM members WHERE updated_at > $1
				ORDER BY updated_at LIMIT 500
			`, since)
			if err == nil {
				result["members"] = scanMembers(rows)
			}
		}
	}

	now := time.Now().Unix()
	c.JSON(200, gin.H{"data": result, "synced_at": now})
}

// ── Push endpoint — receive mutations ─────────────────────────────────────────

func (h *Handler) push(c *gin.Context) {
	var req pushRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		response.BadRequest(c, "VALIDATION_ERROR", err.Error())
		return
	}

	ctx := c.Request.Context()
	results := []map[string]interface{}{}

	for _, m := range req.Mutations {
		// Check idempotency — if already processed, return success
		var existingStatus string
		err := h.db.QueryRow(ctx, `SELECT status FROM sync_mutations WHERE idempotency_key = $1`,
			m.IdempotencyKey).Scan(&existingStatus)
		if err == nil {
			results = append(results, map[string]interface{}{
				"idempotency_key": m.IdempotencyKey,
				"status":          existingStatus,
			})
			continue
		}

		// Insert mutation record
		_, err = h.db.Exec(ctx, `
			INSERT INTO sync_mutations (idempotency_key, client_id, entity_type, entity_id, operation, payload)
			VALUES ($1, $2, $3, $4, $5, $6)
		`, m.IdempotencyKey, m.ClientID, m.EntityType, m.EntityID, m.Operation, m.Payload)
		if err != nil {
			results = append(results, map[string]interface{}{
				"idempotency_key": m.IdempotencyKey,
				"status":          "rejected",
				"error":           "failed to record mutation",
			})
			continue
		}

		// Process immediately (simple server-wins conflict resolution)
		status := "applied"
		_, err = h.db.Exec(ctx, `
			UPDATE sync_mutations SET status = 'applied', processed_at = NOW() WHERE idempotency_key = $1
		`, m.IdempotencyKey)
		if err != nil {
			status = "rejected"
		}

		results = append(results, map[string]interface{}{
			"idempotency_key": m.IdempotencyKey,
			"status":          status,
		})
	}

	response.OK(c, results)
}

// ── Resolve endpoint — conflict resolution ────────────────────────────────────

func (h *Handler) resolve(c *gin.Context) {
	var req resolveRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		response.BadRequest(c, "VALIDATION_ERROR", err.Error())
		return
	}

	ctx := c.Request.Context()
	var exists bool
	_ = h.db.QueryRow(ctx, `SELECT EXISTS(SELECT 1 FROM sync_mutations WHERE id = $1)`, req.MutationID).Scan(&exists)
	if !exists {
		response.NotFound(c, "mutation")
		return
	}

	newStatus := "applied"
	if req.Resolution == "discard" || req.Resolution == "accept_server" {
		newStatus = "rejected"
	}

	_, _ = h.db.Exec(ctx, `UPDATE sync_mutations SET status = $1, processed_at = NOW() WHERE id = $2`,
		newStatus, req.MutationID)

	response.OK(c, gin.H{"mutation_id": req.MutationID, "status": newStatus})
}

// ── Scan helpers ──────────────────────────────────────────────────────────────

func scanItems(rows pgx.Rows) []map[string]interface{} {
	defer rows.Close()
	var results []map[string]interface{}
	for rows.Next() {
		var id, name, category, condition, billingModel, status string
		var description, brand, locationID *string
		var depositAmount, price float64
		var version int
		var updatedAt time.Time
		if rows.Scan(&id, &name, &description, &category, &brand, &condition,
			&billingModel, &depositAmount, &price, &status, &locationID, &version, &updatedAt) == nil {
			results = append(results, map[string]interface{}{
				"id": id, "name": name, "description": description, "category": category,
				"brand": brand, "condition": condition, "billing_model": billingModel,
				"deposit_amount": depositAmount, "price": price, "status": status,
				"location_id": locationID, "version": version,
				"updated_at": updatedAt.UTC().Format(time.RFC3339),
			})
		}
	}
	return results
}

func scanGroupBuys(rows pgx.Rows) []map[string]interface{} {
	defer rows.Close()
	var results []map[string]interface{}
	for rows.Next() {
		var id, itemID, itemName, title, status, locationID string
		var description *string
		var minQty, curQty, version int
		var cutoffAt, updatedAt time.Time
		var pricePerUnit float64
		if rows.Scan(&id, &itemID, &itemName, &title, &description, &minQty,
			&curQty, &status, &cutoffAt, &pricePerUnit, &locationID, &version, &updatedAt) == nil {
			results = append(results, map[string]interface{}{
				"id": id, "item_id": itemID, "item_name": itemName, "title": title,
				"description": description, "min_quantity": minQty, "current_quantity": curQty,
				"status": status, "cutoff_at": cutoffAt.UTC().Format(time.RFC3339),
				"price_per_unit": pricePerUnit, "location_id": locationID,
				"version": version, "updated_at": updatedAt.UTC().Format(time.RFC3339),
			})
		}
	}
	return results
}

func scanOrders(rows pgx.Rows) []map[string]interface{} {
	defer rows.Close()
	var results []map[string]interface{}
	for rows.Next() {
		var id, memberID, status string
		var totalAmount, depositAmount float64
		var groupBuyID *string
		var version int
		var updatedAt time.Time
		if rows.Scan(&id, &memberID, &status, &totalAmount, &depositAmount,
			&groupBuyID, &version, &updatedAt) == nil {
			results = append(results, map[string]interface{}{
				"id": id, "member_id": memberID, "status": status,
				"total_amount": totalAmount, "deposit_amount": depositAmount,
				"group_buy_id": groupBuyID, "version": version,
				"updated_at": updatedAt.UTC().Format(time.RFC3339),
			})
		}
	}
	return results
}

func scanMembers(rows pgx.Rows) []map[string]interface{} {
	defer rows.Close()
	var results []map[string]interface{}
	for rows.Next() {
		var id, userID, membershipType, status string
		var locationID *string
		var version int
		var updatedAt time.Time
		if rows.Scan(&id, &userID, &locationID, &membershipType, &status, &version, &updatedAt) == nil {
			results = append(results, map[string]interface{}{
				"id": id, "user_id": userID, "location_id": locationID,
				"membership_type": membershipType, "status": status,
				"version": version, "updated_at": updatedAt.UTC().Format(time.RFC3339),
			})
		}
	}
	return results
}

package orders

import (
	"context"
	"encoding/json"
	"fmt"
	"strconv"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"

	"fitcommerce/backend/internal/auth"
	"fitcommerce/backend/internal/http/response"
	"fitcommerce/backend/internal/middleware"
	"fitcommerce/backend/internal/modules/audit"
)

type Handler struct {
	db *pgxpool.Pool
}

func NewHandler(db *pgxpool.Pool) *Handler {
	return &Handler{db: db}
}

func (h *Handler) RegisterRoutes(r gin.IRouter) {
	g := r.Group("/orders")
	g.GET("", h.list)
	g.POST("", middleware.RequireRoles(auth.RoleAdministrator, auth.RoleOperationsManager), h.create)
	g.GET("/:id", h.get)
	g.POST("/:id/adjust", middleware.RequireRoles(auth.RoleAdministrator, auth.RoleOperationsManager), h.adjust)
	g.POST("/:id/cancel", middleware.RequireRoles(auth.RoleAdministrator, auth.RoleOperationsManager), h.cancel)
	g.POST("/:id/split", middleware.RequireRoles(auth.RoleAdministrator, auth.RoleOperationsManager), h.split)
	g.POST("/:id/status", middleware.RequireRoles(auth.RoleAdministrator, auth.RoleOperationsManager), h.changeStatus)
	g.GET("/:id/timeline", h.timeline)
	g.POST("/:id/notes", h.addNote)
	g.GET("/:id/notes", h.listNotes)
}

// ── Types ─────────────────────────────────────────────────────────────────────

type createOrderRequest struct {
	MemberID     string      `json:"member_id" binding:"required"`
	LocationID   string      `json:"location_id" binding:"required"`
	GroupBuyID   string      `json:"group_buy_id"`
	TotalAmount  float64     `json:"total_amount" binding:"required"`
	Deposit      float64     `json:"deposit_amount"`
	Notes        string      `json:"notes"`
	Lines        []lineInput `json:"lines" binding:"required,min=1"`
}

type lineInput struct {
	ItemID         string  `json:"item_id" binding:"required"`
	Quantity       int     `json:"quantity" binding:"required,min=1"`
	UnitPrice      float64 `json:"unit_price" binding:"required"`
	DepositPerUnit float64 `json:"deposit_per_unit"`
}

type adjustRequest struct {
	LineID      string  `json:"line_id" binding:"required"`
	NewQuantity int     `json:"new_quantity" binding:"required,min=1"`
	Reason      string  `json:"reason" binding:"required"`
}

type splitRequest struct {
	Lines  []splitLine `json:"lines" binding:"required,min=1"`
	Reason string      `json:"reason" binding:"required"`
}

type splitLine struct {
	LineID   string `json:"line_id" binding:"required"`
	Quantity int    `json:"quantity" binding:"required,min=1"`
}

type statusChangeRequest struct {
	Status string `json:"status" binding:"required"`
	Reason string `json:"reason" binding:"required"`
}

type noteRequest struct {
	Content string `json:"content" binding:"required"`
}

type orderResponse struct {
	ID           string         `json:"id"`
	GroupBuyID   *string        `json:"group_buy_id"`
	MemberID     string         `json:"member_id"`
	LocationID   string         `json:"location_id"`
	Status       string         `json:"status"`
	TotalAmount  float64        `json:"total_amount"`
	Deposit      float64        `json:"deposit_amount"`
	Notes        *string        `json:"notes"`
	CreatedBy    *string        `json:"created_by"`
	CreatedAt    string         `json:"created_at"`
	UpdatedAt    string         `json:"updated_at"`
	Version      int            `json:"version"`
	Lines        []lineResponse `json:"lines,omitempty"`
}

type lineResponse struct {
	ID             string  `json:"id"`
	OrderID        string  `json:"order_id"`
	ItemID         string  `json:"item_id"`
	Quantity       int     `json:"quantity"`
	UnitPrice      float64 `json:"unit_price"`
	DepositPerUnit float64 `json:"deposit_per_unit"`
}

type noteResponse struct {
	ID        string `json:"id"`
	OrderID   string `json:"order_id"`
	AuthorID  string `json:"author_id"`
	Content   string `json:"content"`
	CreatedAt string `json:"created_at"`
}

type timelineEvent struct {
	ID          string          `json:"id"`
	OrderID     string          `json:"order_id"`
	ActorID     *string         `json:"actor_id"`
	EventType   string          `json:"event_type"`
	Description string          `json:"description"`
	Before      json.RawMessage `json:"before_snapshot"`
	After       json.RawMessage `json:"after_snapshot"`
	OccurredAt  string          `json:"occurred_at"`
}

// ── Helpers ───────────────────────────────────────────────────────────────────


// ── Handlers ──────────────────────────────────────────────────────────────────

func (h *Handler) list(c *gin.Context) {
	role := c.GetString(middleware.KeyRole)
	userID := c.GetString(middleware.KeyUserID)

	page, _ := strconv.Atoi(c.DefaultQuery("page", "1"))
	perPage, _ := strconv.Atoi(c.DefaultQuery("per_page", "25"))
	if page < 1 {
		page = 1
	}
	if perPage < 1 || perPage > 100 {
		perPage = 25
	}

	baseQuery := `FROM orders WHERE 1=1`
	args := []interface{}{}
	argIdx := 1

	// Members see only their own orders
	if role == auth.RoleMember {
		var memberID string
		err := h.db.QueryRow(c.Request.Context(), `SELECT id FROM members WHERE user_id = $1`, userID).Scan(&memberID)
		if err != nil {
			response.OK(c, []interface{}{})
			return
		}
		baseQuery += fmt.Sprintf(" AND member_id = $%d", argIdx)
		args = append(args, memberID)
		argIdx++
	}

	if status := c.Query("status"); status != "" {
		baseQuery += fmt.Sprintf(" AND status = $%d", argIdx)
		args = append(args, status)
		argIdx++
	}

	var total int
	_ = h.db.QueryRow(c.Request.Context(), "SELECT COUNT(*) "+baseQuery, args...).Scan(&total)

	query := `SELECT id, group_buy_id, member_id, location_id, status, total_amount, deposit_amount, notes, created_by, created_at, updated_at, version ` +
		baseQuery + fmt.Sprintf(" ORDER BY created_at DESC LIMIT $%d OFFSET $%d", argIdx, argIdx+1)
	args = append(args, perPage, (page-1)*perPage)

	rows, err := h.db.Query(c.Request.Context(), query, args...)
	if err != nil {
		response.InternalError(c)
		return
	}
	defer rows.Close()

	orders := []orderResponse{}
	for rows.Next() {
		o := h.scanOrder(rows)
		if o == nil {
			response.InternalError(c)
			return
		}
		orders = append(orders, *o)
	}

	response.OKPaginated(c, orders, response.Meta{Page: page, PerPage: perPage, Total: total})
}

func (h *Handler) create(c *gin.Context) {
	var req createOrderRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		response.BadRequest(c, "VALIDATION_ERROR", err.Error())
		return
	}

	ctx := c.Request.Context()
	userID := c.GetString(middleware.KeyUserID)

	tx, err := h.db.Begin(ctx)
	if err != nil {
		response.InternalError(c)
		return
	}
	defer tx.Rollback(ctx)

	var gbID *string
	if req.GroupBuyID != "" {
		gbID = &req.GroupBuyID
	}
	var notes *string
	if req.Notes != "" {
		notes = &req.Notes
	}

	var orderID string
	var createdAt, updatedAt time.Time
	err = tx.QueryRow(ctx, `
		INSERT INTO orders (group_buy_id, member_id, location_id, total_amount, deposit_amount, notes, created_by)
		VALUES ($1, $2, $3, $4, $5, $6, $7)
		RETURNING id, created_at, updated_at
	`, gbID, req.MemberID, req.LocationID, req.TotalAmount, req.Deposit, notes, userID,
	).Scan(&orderID, &createdAt, &updatedAt)
	if err != nil {
		response.InternalError(c)
		return
	}

	lines := []lineResponse{}
	for _, l := range req.Lines {
		var lineID string
		err = tx.QueryRow(ctx, `
			INSERT INTO order_line_items (order_id, item_id, quantity, unit_price, deposit_per_unit)
			VALUES ($1, $2, $3, $4, $5) RETURNING id
		`, orderID, l.ItemID, l.Quantity, l.UnitPrice, l.DepositPerUnit).Scan(&lineID)
		if err != nil {
			response.InternalError(c)
			return
		}
		lines = append(lines, lineResponse{
			ID: lineID, OrderID: orderID, ItemID: l.ItemID,
			Quantity: l.Quantity, UnitPrice: l.UnitPrice, DepositPerUnit: l.DepositPerUnit,
		})
	}

	// Timeline: creation
	_, _ = tx.Exec(ctx, `
		INSERT INTO order_timeline_events (order_id, actor_id, event_type, description)
		VALUES ($1, $2, 'creation', $3)
	`, orderID, userID, fmt.Sprintf("Order created with %d line items, total $%.2f", len(lines), req.TotalAmount))

	if err := tx.Commit(ctx); err != nil {
		response.InternalError(c)
		return
	}

	audit.Log(ctx, h.db, &userID, "order.create", "order", orderID, nil, req, c.ClientIP())

	response.Created(c, orderResponse{
		ID: orderID, GroupBuyID: gbID, MemberID: req.MemberID, LocationID: req.LocationID,
		Status: "pending", TotalAmount: req.TotalAmount, Deposit: req.Deposit, Notes: notes,
		CreatedBy: &userID, CreatedAt: createdAt.UTC().Format(time.RFC3339),
		UpdatedAt: updatedAt.UTC().Format(time.RFC3339), Version: 1, Lines: lines,
	})
}

func (h *Handler) get(c *gin.Context) {
