import { apiRequest } from './client';

export interface Item {
  id: string;
  name: string;
  sku: string | null;
  category: string;
  brand: string | null;
  condition: string;
  description: string | null;
  images: string[];
  deposit_amount: number;
  billing_model: string;
  price: number;
  status: string;
  location_id: string | null;
  created_by: string | null;
  created_at: string;
  updated_at: string;
  version: number;
}

export interface ItemListResponse {
  data: Item[];
  meta: { page: number; per_page: number; total: number };
}

export interface AvailabilityWindow {
  id: string;
  item_id: string;
  starts_at: string;
  ends_at: string;
  created_at: string;
}

export interface CreateItemPayload {
  name: string;
  sku?: string;
  category: string;
  brand?: string;
  condition?: string;
  description?: string;
  images?: string[];
  deposit_amount?: number;
  billing_model?: string;
  price: number;
  location_id?: string;
}

export interface UpdateItemPayload {
  name?: string;
  sku?: string;
  category?: string;
  brand?: string;
  condition?: string;
  description?: string;
  images?: string[];
  deposit_amount?: number;
  billing_model?: string;
  price?: number;
}

export interface BatchUpdatePayload {
  item_ids: string[];
  price?: number;
}

export async function listItems(params?: Record<string, string>): Promise<ItemListResponse> {
  const qs = params ? '?' + new URLSearchParams(params).toString() : '';
  const res = await fetch(
    `${import.meta.env.VITE_API_URL ?? 'http://localhost:8080'}/api/v1/items${qs}`,
    {
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${localStorage.getItem('fc_access_token')}`,
      },
    },
  );
  return res.json();
}

export function getItem(id: string): Promise<Item> {
  return apiRequest<Item>(`/api/v1/items/${id}`);
}

export function createItem(payload: CreateItemPayload): Promise<Item> {
  return apiRequest<Item>('/api/v1/items', {
    method: 'POST',
    body: JSON.stringify(payload),
  });
}

export function updateItem(id: string, payload: UpdateItemPayload): Promise<Item> {
  return apiRequest<Item>(`/api/v1/items/${id}`, {
    method: 'PATCH',
    body: JSON.stringify(payload),
  });
}

export function deleteItem(id: string): Promise<void> {
  return apiRequest(`/api/v1/items/${id}`, { method: 'DELETE' });
}

export function publishItem(id: string): Promise<Item> {
  return apiRequest<Item>(`/api/v1/items/${id}/publish`, { method: 'POST' });
}

export function unpublishItem(id: string): Promise<Item> {
  return apiRequest<Item>(`/api/v1/items/${id}/unpublish`, { method: 'POST' });
}

export function batchUpdateItems(payload: BatchUpdatePayload): Promise<{ updated: number }> {
  return apiRequest('/api/v1/items/batch', {
    method: 'POST',
    body: JSON.stringify(payload),
  });
}

export function listAvailabilityWindows(itemId: string): Promise<AvailabilityWindow[]> {
  return apiRequest<AvailabilityWindow[]>(`/api/v1/items/${itemId}/availability-windows`);
}

export function addAvailabilityWindow(
  itemId: string,
  starts_at: string,
  ends_at: string,
): Promise<AvailabilityWindow> {
  return apiRequest<AvailabilityWindow>(`/api/v1/items/${itemId}/availability-windows`, {
    method: 'POST',
    body: JSON.stringify({ starts_at, ends_at }),
  });
}

export function deleteAvailabilityWindow(itemId: string, windowId: string): Promise<void> {
  return apiRequest(`/api/v1/items/${itemId}/availability-windows/${windowId}`, {
    method: 'DELETE',
  });
}

