		"churn_rate":      rate,
		"start_date":      start.Format("2006-01-02"),
		"end_date":        end.Format("2006-01-02"),
	})
}

// ── KPI: Inventory Report ─────────────────────────────────────────────────────

func (h *Handler) inventoryReport(c *gin.Context) {
	ctx := c.Request.Context()

	type stockSummary struct {
